<?php
if ( ! current_user_can( 'creditrack_view_audit' ) ) { wp_die( 'Access denied.', '', array( 'response' => 403 ) ); }
$action_filter = sanitize_key( $_GET['audit_action'] ?? '' ); $where = $action_filter ? $wpdb->prepare( 'WHERE a.action=%s', $action_filter ) : ''; $entries = $wpdb->get_results( "SELECT a.*,u.display_name FROM {$wpdb->prefix}ct_audit_logs a LEFT JOIN {$wpdb->users} u ON u.ID=a.actor_user_id $where ORDER BY a.created_at DESC LIMIT 200" );
?><div class="ct-titlebar"><div><h1>Audit log</h1><div class="ct-muted">Append-only security and business activity.</div></div></div><form class="ct-toolbar" method="get"><label for="audit_action">Action</label><input id="audit_action" name="audit_action" value="<?php echo esc_attr( $action_filter ); ?>" placeholder="e.g. create, post, reverse"><button type="submit">Filter</button></form><div class="ct-table-wrap"><table><thead><tr><th>Timestamp (UTC)</th><th>Actor</th><th>Action</th><th>Entity</th><th>Description</th><th>IP</th></tr></thead><tbody><?php foreach ( $entries as $entry ) { ?><tr><td><?php echo esc_html( $entry->created_at ); ?></td><td><?php echo esc_html( $entry->display_name ?: 'System' ); ?></td><td><?php echo esc_html( $entry->action ); ?></td><td><?php echo esc_html( $entry->entity_type . ( $entry->entity_id ? ' #' . $entry->entity_id : '' ) ); ?></td><td><?php echo esc_html( $entry->description ); ?></td><td><?php echo esc_html( $entry->ip_address ); ?></td></tr><?php } if ( ! $entries ) { ?><tr><td colspan="6">No audit events match this filter.</td></tr><?php } ?></tbody></table></div>
